import React, { useEffect, useState } from "react";
import { useParams, Link } from "react-router-dom";
import axios from "axios";

const API_BASE = process.env.REACT_APP_API_BASE || "http://localhost:8000";

export default function RoomDetails() {
  const { id } = useParams();

  const [room, setRoom] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");

  /* ================= FETCH ROOM ================= */
  useEffect(() => {
    if (!id) {
      setError("Invalid room");
      setLoading(false);
      return;
    }

    axios
      .get(`${API_BASE}/api/rooms/${id}/`)
      .then((res) => setRoom(res.data))
      .catch(() => setError("Room not found"))
      .finally(() => setLoading(false));
  }, [id]);

  /* ================= SAFE ANIMATIONS ================= */
  useEffect(() => {
    if (loading) return;

    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (entry.isIntersecting) {
            entry.target.classList.add("show");
            observer.unobserve(entry.target);
          }
        });
      },
      { threshold: 0.1 }
    );

    document
      .querySelectorAll(
        ".fade-in, .fade-up, .fade-left, .fade-right, .amenity"
      )
      .forEach((el) => observer.observe(el));

    return () => observer.disconnect();
  }, [loading]);

  if (loading) return <p style={{ padding: 40 }}>Loading...</p>;
  if (error) return <p style={{ padding: 40 }}>{error}</p>;
  if (!room) return null;

  const image =
    room.image
      ? room.image.startsWith("http")
        ? room.image
        : `${API_BASE}${room.image}`
      : "/assets/images/room_blur.png";

  return (
    <>
      {/* ================= INLINE CSS ================= */}
      <style>{`
        body {
          margin: 0;
          font-family: 'Montserrat', sans-serif;
          background: #fff;
          color: #333;
        }

        /* NAV */
        .nav {
          position: absolute;
          width: 100%;
          top: 0;
          z-index: 10;
        }
        .nav-inner {
          display: flex;
          justify-content: space-between;
          align-items: center;
          padding: 20px 60px;
        }
        .logo {
          height: 50px;
        }
        .menu a {
          margin-left: 20px;
          text-decoration: none;
          color: #fff;
          font-weight: 500;
        }
        .menu .reserve {
          padding: 8px 16px;
          border: 1px solid #fff;
          border-radius: 4px;
        }

        /* HERO */
        .hero {
          height: 90vh;
          display: flex;
          align-items: center;
          justify-content: center;
          color: #fff;
          text-align: center;
        }
        .hero-overlay {
          background: rgba(0,0,0,0.45);
          padding: 40px;
        }
        .hero h1 {
          font-family: 'Playfair Display', serif;
          font-size: 56px;
          margin-bottom: 10px;
        }
        .breadcrumb {
          margin-top: 10px;
          font-size: 14px;
        }
        .breadcrumb a {
          color: #fff;
          text-decoration: none;
        }

        /* ROOM DETAILS */
        .room-details {
          padding: 80px 20px;
          text-align: center;
        }
        .room-title {
          font-family: 'Playfair Display', serif;
          font-size: 42px;
        }
        .room-price-box {
          margin: 30px auto;
        }
        .price {
          font-size: 26px;
          font-weight: 600;
        }
        .reserve-btn {
          display: inline-block;
          margin-top: 15px;
          padding: 12px 30px;
          background: #000;
          color: #fff;
          text-decoration: none;
        }
        .room-description {
          max-width: 800px;
          margin: 40px auto;
          line-height: 1.7;
        }

        /* GALLERY */
        .room-gallery {
          max-width: 1000px;
          margin: 40px auto;
          overflow: hidden;
        }
        .room-gallery img {
          width: 100%;
          height: 500px;
          object-fit: cover;
        }

        /* AMENITIES */
        .room-amenities {
          padding: 80px 20px;
          background: #f8f8f8;
        }
        .amenities-container {
          display: grid;
          grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
          gap: 20px;
          max-width: 1100px;
          margin: auto;
        }
        .amenity {
          text-align: center;
          font-size: 16px;
        }

        /* FOOTER */
        .footer {
          background: #111;
          color: #fff;
          padding: 40px;
        }
        .footer-inner {
          display: flex;
          justify-content: space-between;
          flex-wrap: wrap;
        }

        /* ANIMATIONS (SAFE) */
        .fade-in, .fade-up, .fade-left, .fade-right, .amenity {
          opacity: 1;
        }
        .fade-up.show {
          animation: fadeUp 0.8s ease forwards;
        }
        .fade-in.show {
          animation: fadeIn 0.8s ease forwards;
        }
        @keyframes fadeUp {
          from { opacity: 0; transform: translateY(40px); }
          to { opacity: 1; transform: translateY(0); }
        }
        @keyframes fadeIn {
          from { opacity: 0; }
          to { opacity: 1; }
        }
      `}</style>

      {/* ================= NAV ================= */}
      <header className="nav fade-in">
        <div className="nav-inner">
          <img src="/assets/images/glamp_logo.png" alt="Logo" className="logo" />
          <nav className="menu">
            <Link to="/">Home</Link>
            <Link to="/reservation">Reservation</Link>
            <Link className="reserve" to="/reservation">Reserve</Link>
          </nav>
        </div>
      </header>

      {/* ================= HERO ================= */}
      <section
        className="hero fade-up"
        style={{
          background: `url("${image}") center/cover no-repeat`,
        }}
      >
        <div className="hero-overlay">
          <h1 className="fade-in">{room.room_name}</h1>
          <p className="fade-up">
            Experience nature with unmatched comfort & elegance
          </p>
          <div className="breadcrumb fade-in">
            <Link to="/">Home</Link> / Room Details
          </div>
        </div>
      </section>

      {/* ================= DETAILS ================= */}
      <section className="room-details fade-up">
        <h2 className="room-title fade-in">{room.room_name}</h2>

        <div className="room-price-box fade-up">
          <div className="price">₹{Number(room.price).toFixed(2)} / night</div>
          <Link to="/reservation" className="reserve-btn">RESERVE NOW</Link>
        </div>

        <p className="room-description fade-up">{room.description}</p>

        <div className="room-gallery fade-up">
          <img src={image} alt="Room" />
        </div>
      </section>

      {/* ================= AMENITIES ================= */}
      <section className="room-amenities fade-up">
        <div className="amenities-container">
          {[
            "4 Guests","35 Feet Size","Connecting Rooms","1 King Bed",
            "Cable TV","Shower","Work Desk","Bathtub",
            "Safebox","Free WiFi","Balcony","City View",
          ].map((item) => (
            <div className="amenity" key={item}>{item}</div>
          ))}
        </div>
      </section>

      {/* ================= FOOTER ================= */}
      <footer className="footer fade-in">
        <div className="footer-inner">
          <div>
            <h4>Address</h4>
            <p>Adimali, Idukki, Kerala</p>
          </div>
          <div>
            <h4>Contact</h4>
            <p>+91 9497185771</p>
          </div>
        </div>
      </footer>
    </>
  );
}
